<script setup lang="ts">
import { computed, ref, watch } from "vue";
import { REVIEW_GATES, REVIEW_TARGET_IDS, createReviewDocument, exportReviewDocument, importReviewDocument, reviewReleaseReady, updateReviewGate, type ReviewDecision, type ReviewDocument, type ReviewGateId } from "../core/reviewWizard";
import { getInstrumentChassisUrl } from "../core/instrumentSkins";
import { VIRTUAL_INSTRUMENT_DEFINITIONS } from "../core/virtualInstrumentCatalog";
import type { PercussionGridTile } from "../core/percussionGrid";
import ClassroomInstrumentActivity from "./ClassroomInstrumentActivity.vue";
import FixedTabletStage from "./FixedTabletStage.vue";
import PercussionGrid from "./PercussionGrid.vue";
import VirtualInstrumentPlayer from "./VirtualInstrumentPlayer.vue";

const props=withDefaults(defineProps<{modelValue?:ReviewDocument;persistKey?:string}>(),{persistKey:"virtual-instrument-review-v2"});
const emit=defineEmits<{"update:modelValue":[value:ReviewDocument];reviewchange:[value:ReviewDocument]}>();
function initial(){if(props.modelValue)return props.modelValue;try{const value=localStorage.getItem(props.persistKey);return value?importReviewDocument(value):createReviewDocument()}catch{return createReviewDocument()}}
const document=ref(initial());const targetIndex=ref(0);const gateIndex=ref(0);const overlay=ref(true);const performanceMode=ref(false);const importInput=ref<HTMLInputElement|null>(null);
const targetId=computed(()=>REVIEW_TARGET_IDS[targetIndex.value]);const target=computed(()=>VIRTUAL_INSTRUMENT_DEFINITIONS.find(item=>item.id===targetId.value));const gate=computed(()=>REVIEW_GATES[gateIndex.value]);const record=computed(()=>document.value.targets[targetId.value].gates[gate.value.id]);
const isMalletTarget=computed(()=>target.value?.family==="mallet");const malletDisplayImage=computed(()=>isMalletTarget.value?getInstrumentChassisUrl(targetId.value):null);const showsMalletDisplay=computed(()=>gate.value.id==="visual"&&isMalletTarget.value&&!performanceMode.value);
const decisionLabel=computed(()=>({approved:"已通过",modify:"需要修改",rejected:"已拒绝",pending:"等待审核"}[record.value.decision]??"等待审核"));
const percussion=VIRTUAL_INSTRUMENT_DEFINITIONS.filter(item=>item.family==="percussion");const colors=["clay","slate","oak","sage","violet","brass"];
const gridTiles:PercussionGridTile[]=percussion.map((item,index)=>({id:`review-${item.id}`,instrumentId:item.id,zoneId:item.zones[0].id,colorToken:colors[index]}));
const activityConfig=computed(()=>({mode:"steady_beat" as const,target:targetId.value==="virtual_percussion_grid"?{type:"percussion_grid" as const,tiles:gridTiles}:{type:"instrument" as const,instrumentId:targetId.value},gradePreset:"middle_primary" as const,metronome:{bpm:100,meter:"4/4" as const,countInBars:1 as const,continueDuringPerformance:false,subdivision:"beat" as const},demoSequence:[{zoneId:target.value?.zones[0]?.id??"midi-60",beatOffset:0,durationBeats:.25},{zoneId:target.value?.zones[0]?.id??"midi-60",beatOffset:1,durationBeats:.25}]}));
function decide(decision:ReviewDecision){updateReviewGate(document.value,targetId.value,gate.value.id,decision,record.value.notes);document.value={...document.value};emit("update:modelValue",document.value);emit("reviewchange",document.value);if(decision==="approved")next()}
function notes(value:string){record.value.notes=value;document.value={...document.value};emit("reviewchange",document.value)}
function next(){if(gateIndex.value<REVIEW_GATES.length-1)gateIndex.value++;else if(targetIndex.value<REVIEW_TARGET_IDS.length-1){targetIndex.value++;gateIndex.value=0}}
function previous(){if(gateIndex.value>0)gateIndex.value--;else if(targetIndex.value>0){targetIndex.value--;gateIndex.value=REVIEW_GATES.length-1}}
function download(){const blob=new Blob([exportReviewDocument(document.value)],{type:"application/json"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download="virtual-instrument-review-v2.json";a.click();URL.revokeObjectURL(url)}
function upload(event:Event){const file=(event.target as HTMLInputElement).files?.[0];if(!file)return;file.text().then(text=>{document.value=importReviewDocument(text);emit("reviewchange",document.value)})}
watch(document,value=>{try{localStorage.setItem(props.persistKey,exportReviewDocument(value))}catch{}},{deep:true});
watch([targetIndex,gateIndex],()=>{performanceMode.value=false});
</script>
<template><main class="wizard"><header class="wizard-hero"><div><p>音乐教师交付审核</p><h1>虚拟乐器顺序审核向导</h1><span>十件乐器＋打击乐六宫格 · 每项必须依次通过五道门槛</span></div><div class="release" :data-ready="reviewReleaseReady(document)"><strong>{{ reviewReleaseReady(document)?'允许交付':'暂不可交付' }}</strong><small>任一项“修改 / 拒绝 / 待审核”都会阻止发布</small></div></header>
<div class="wizard-grid"><nav class="targets"><button v-for="(id,index) in REVIEW_TARGET_IDS" :key="id" :class="{active:index===targetIndex}" @click="targetIndex=index;gateIndex=0"><span>{{ String(index+1).padStart(2,'0') }}</span><b>{{ VIRTUAL_INSTRUMENT_DEFINITIONS.find(item=>item.id===id)?.name??'打击乐六宫格' }}</b><i>{{ REVIEW_GATES.filter(g=>document.targets[id].gates[g.id].decision==='approved').length }}/5</i></button></nav>
<section class="workspace"><div class="stepper"><button v-for="(item,index) in REVIEW_GATES" :key="item.id" :class="{active:index===gateIndex}" :data-decision="document.targets[targetId].gates[item.id].decision" @click="gateIndex=index"><span>{{ index+1 }}</span>{{ item.label }}</button></div>
<div class="preview"><div class="preview-head"><div><p>目标 {{ targetIndex+1 }}/11 · 步骤 {{ gateIndex+1 }}/5</p><h2>{{ target?.name??'打击乐六宫格' }} / {{ gate.label }}</h2><span>{{ gate.description }}</span></div><button v-if="gate.id==='visual'&&isMalletTarget&&performanceMode" class="return-display" @click="performanceMode=false">返回整体展示</button><label v-else-if="gate.id==='touch'"><input v-model="overlay" type="checkbox">显示热区、坐标和最近点击</label></div>
<ClassroomInstrumentActivity v-if="gate.id==='metronome'||gate.id==='gameplay'" :config="activityConfig"/>
<FixedTabletStage v-else review-mode><div class="stage-pad"><button v-if="showsMalletDisplay" class="mallet-display-card" @click="performanceMode=true"><img :src="malletDisplayImage??''" :alt="`${target?.name}完整乐器展示`"><span><b>{{ target?.name }}</b><small>点击图片进入可触控演奏界面</small><strong>进入演奏模式</strong></span></button><PercussionGrid v-else-if="!target" :tiles="gridTiles" :review-mode="gate.id==='touch'&&overlay"/><VirtualInstrumentPlayer v-else :instrument-id="target.id" :show-controls="gate.id==='audio'" :review-mode="gate.id==='touch'&&overlay"/></div></FixedTabletStage></div>
<aside class="decision"><div><span>当前结论</span><strong :data-decision="record.decision">{{ decisionLabel }}</strong></div><textarea :value="record.notes" rows="4" placeholder="写下音乐性、软件性或课堂可用性的具体意见" @input="notes(($event.target as HTMLTextAreaElement).value)"/><div class="decision-actions"><button class="approve" @click="decide('approved')">通过并进入下一项</button><button @click="decide('modify')">修改</button><button class="reject" @click="decide('rejected')">拒绝</button></div><footer><button @click="previous">上一步</button><button @click="next">下一步</button><button @click="download">导出审核记录</button><button @click="importInput?.click()">导入审核记录</button><input ref="importInput" type="file" accept="application/json" hidden @change="upload"></footer></aside></section></div></main></template>
<style scoped>:global(*){box-sizing:border-box}:global(body){margin:0;background:#d7cfbd;color:#24231f;font-family:"Avenir Next","PingFang SC",sans-serif}.wizard{min-height:100vh;padding:28px;background:linear-gradient(90deg,#2d2a2409 1px,transparent 1px),linear-gradient(#2d2a2409 1px,transparent 1px),#d7cfbd;background-size:24px 24px}.wizard-hero{display:flex;justify-content:space-between;gap:24px;max-width:1600px;margin:auto;padding-bottom:20px;border-bottom:1px solid #312e2733}.wizard-hero p,.preview-head p{margin:0;color:#9e542f;font-size:10px;font-weight:900;letter-spacing:.18em}.wizard-hero h1{margin:6px 0;font:500 48px/1 "Songti SC",serif}.wizard-hero span{color:#6d675d}.release{align-self:center;min-width:245px;padding:17px;color:#f4e9d5;background:#8b463c;border-radius:18px}.release[data-ready=true]{background:#315d4b}.release strong,.release small{display:block}.release small{margin-top:5px;opacity:.7}.wizard-grid{display:grid;grid-template-columns:190px 1fr;gap:14px;max-width:1600px;margin:18px auto}.targets{display:flex;flex-direction:column;gap:5px}.targets button{display:grid;grid-template-columns:28px 1fr auto;gap:7px;align-items:center;padding:10px;border:1px solid #39352d22;border-radius:9px;background:#eee7d8;text-align:left}.targets button.active{color:#f4ead8;background:#29332f}.targets span{color:#a65d37;font-size:9px}.targets i{font-size:10px}.workspace{min-width:0}.stepper{display:grid;grid-template-columns:repeat(5,1fr);gap:5px;margin-bottom:8px}.stepper button{padding:10px;border:0;border-radius:9px;background:#eee7d8}.stepper button.active{color:#f5ead6;background:#29332f}.stepper button[data-decision=approved] span{background:#4e8b65}.stepper span{display:inline-grid;place-items:center;width:20px;height:20px;margin-right:6px;border-radius:50%;background:#b4aa99}.preview{padding:13px;border-radius:20px;background:#1a211f}.preview-head{display:flex;justify-content:space-between;align-items:end;margin-bottom:10px;color:#eee5d4}.preview-head h2{margin:4px 0;font:500 30px/1 "Songti SC",serif}.preview-head span{color:#aaa191;font-size:11px}.preview-head label{font-size:11px}.return-display{padding:9px 14px;border:1px solid #e5c28d55;border-radius:999px;color:#f1dec1;background:#8e5d37;font-weight:700}.preview :deep(.tablet-host){height:min(58vw,768px)}.stage-pad{width:1024px;height:768px;padding:22px}.stage-pad>:deep(.instrument),.stage-pad>:deep(.percussion-grid-shell){height:724px}.mallet-display-card{position:relative;display:grid;place-items:center;width:100%;height:724px;overflow:hidden;padding:0;border:1px solid #fff2;border-radius:28px;color:#f4ead8;background:radial-gradient(circle at 50% 42%,#6b4a3066,transparent 42%),linear-gradient(145deg,#1c2422,#0b1011);box-shadow:inset 0 0 0 1px #fff1;cursor:pointer}.mallet-display-card img{width:82%;height:78%;object-fit:contain;filter:drop-shadow(0 28px 28px #000b);transition:transform .28s ease,filter .28s ease}.mallet-display-card span{position:absolute;left:32px;right:32px;bottom:26px;display:grid;grid-template-columns:auto 1fr auto;gap:18px;align-items:center;padding:15px 18px;border:1px solid #fff2;border-radius:17px;background:#111715db;backdrop-filter:blur(14px);text-align:left}.mallet-display-card b{font:500 30px/1 "Songti SC",serif}.mallet-display-card small{color:#b8ad9d}.mallet-display-card strong{padding:10px 15px;border-radius:999px;color:#22170f;background:#e3b073}.mallet-display-card:hover img{transform:scale(1.025);filter:drop-shadow(0 32px 32px #000d) brightness(1.06)}.mallet-display-card:focus-visible{outline:3px solid #e3b073;outline-offset:-6px}.decision{display:grid;grid-template-columns:auto minmax(220px,1fr) auto;gap:10px;align-items:center;margin-top:8px;padding:13px;border-radius:16px;background:#eee7d8}.decision>div:first-child span,.decision>div:first-child strong{display:block}.decision strong{margin-top:4px}.decision textarea{padding:10px;border:1px solid #5b544733;border-radius:9px;background:#fff9}.decision-actions{display:grid;grid-template-columns:1fr 1fr;gap:5px}.decision-actions button,.decision footer button{padding:9px;border:0;border-radius:8px;background:#d8a766}.decision-actions .approve{grid-column:1/-1;color:#fff;background:#315d4b}.decision-actions .reject{color:#fff;background:#8b463c}.decision footer{grid-column:1/-1;display:flex;gap:5px;justify-content:flex-end}.decision footer button{background:#d5ccbb}@media(max-width:1000px){.wizard-grid{grid-template-columns:1fr}.targets{display:grid;grid-template-columns:repeat(6,1fr)}.decision{grid-template-columns:1fr}.decision footer{grid-column:auto}.wizard-hero{flex-direction:column}.release{align-self:stretch}}</style>
